import Card from "@material-ui/core/Card";
import CardActions from "@material-ui/core/CardActions";
import CardContent from "@material-ui/core/CardContent";
import CardMedia from "@material-ui/core/CardMedia";
import { makeStyles, StylesProvider } from "@material-ui/core/styles";

import Button from "@material-ui/core/Button";
import myImg from "./srija.jpg";
import { useNavigate } from "react-router-dom";
import { Box, Divider, Grid, Typography } from "@material-ui/core";

import React, { useEffect, useState } from "react";
import image1 from "./assets/1.jpg";
import image2 from "./assets/2.jpg"
import image3 from "./assets/3.jpg";
import obama from "./assets/intro.jpeg";
import intromeme2 from "./assets/intro2.jpeg"
import tinkertext from "./assets/introtinkertext.gif"
import tinker from "./assets/tinker.gif"
import image4 from "./assets/4.jpg";
import image5 from "./assets/5.jpg";
import image6 from "./assets/6.jpg";
import image9 from "./assets/9.jpg";
import image7 from "./assets/7.jpg";

import image21 from "./assets/21.jpg";
import image8 from "./assets/8.jpg";
import ChevronRightIcon from "@mui/icons-material/ChevronRight";
import clanguage from "./assets/c.png";
import python from "./assets/python.png";
import java from "./assets/java.png";
import linux from "./assets/linux.png";
// import apache from "./assets/apache.png";
// import php from "./assets/php.png";
import wireshark from "./assets/wireshark.png";
import mysql from "./assets/mysql.png";
// import capsa from "./assets/capsa.png";
// import ntop from "./assets/ntop.webp";
import node from "./assets/node.png";
import latex from "./assets/latex.png";
import git from "./assets/github.png";
import react from "./assets/react.png";
import intromeme from "./assets/intromeme.jpeg";
import image22 from "./assets/22.jpeg";
const useStyles = makeStyles((theme) => ({

  rotateIcon: {
    transform: "rotate(90deg)",
  },
}));

const About = () => {
  const navigate = useNavigate();
  let pixel = 0;

  const [mousePos, setMousePos] = useState({});
  const classes = useStyles();
  const [skills, showSkills] = useState(false);
  const [hover1, setHover1] = useState(false);
  const [hover2, setHover2] = useState(false);
  const handleArt = () => {
    navigate("/art");
  };
  const handleProjects = () => {
    navigate("/projects");
  };
  useEffect(() => {
    const handleMouseMove = (event) => {
      setMousePos({ x: event.clientX, y: event.clientY });
    };

    window.addEventListener("mousemove", handleMouseMove);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
    };
  }, []);
  if (parseInt(mousePos.x) <= 1062) {
    pixel = 1065 - parseInt(mousePos.x);
  } else {
    pixel = parseInt(mousePos.x) - 763;
  }
  const styles = {
    width: hover1 ? `calc(70% + ${pixel}px)` : "70%",
    // background: "#CFA294",
    background: "#EFEFEF",
    height: "150px",
    left: 0,
    position: "absolute",
    zIndex: hover1 ? 3 : 1,
    transition: "1000ms",
    maxWidth: "100%",
    borderRadius: "0px 10px 10px 0px",
  };
  const styles1 = {
    width: hover2 ? `calc(70% + ${pixel}px)` : "70%",
    // background: "#A64E4D",
    background: "#EFEFEF",
    // height: "150px",
    overflowX: "hidden",
    // textAlign: "center",
    // marginTop: "-320px",
    right: 0,
    position: "absolute",
    zIndex: hover2 ? 3 : 1,
    maxWidth: "100%",
    transition: "1000ms",
    borderRadius: "10px 0px 0px 10px",
  };
  return (
    <React.Fragment>
      <div className="App">
        <div
          style={{
            height: "300px",
            marginTop: '50px',
            // width: "900px",
            display: "flex",
            // alignItems: "center",
            flexDirection: "row",
            margin: "0 auto",
          }}
        >
          <span>
            <img src={tinker} style={{height: '200px'}}></img>
          </span>
          <span
            style={{
              color: "#888",
              fontSize: "25px",
              fontWeight: "lighter",
              textAlign: "left",
              // width:'500px'
              // marginLeft: "40px",
            }}
          >
            {/* <p> Let me introduce myself</p> */}
            A recent graduate with an Integrated Master of Technology in
            Computer Science from University of Hyderabad. I've enjoyed
            understanding complex algorithms and designing websites. When I'm not working you'll find me
            binge watching or painting.
          </span>
          <span>
          {/* <div style={{ paddingTop: "10px", width: '400px' }}>
              <Grid container spacing={2}>
                <Grid item xs={10}>
                  <Button
                    onClick={(e) => {
                      showSkills(!skills);
                    }}
                    startIcon={
                      skills ? (
                        <ChevronRightIcon className={classes.rotateIcon} />
                      ) : (
                        <ChevronRightIcon />
                      )
                    }
                  >
                    Skills
                  </Button>
                  {skills && (
                    <div
                      style={{
                        // height: "10px",
                        width: "200px",
                        // padding: "10px 0px 0px 30px",
                        display: "flex",
                        flexDirection: "column",
                      }}
                    >
                      <div style={{ display: "flex", flexDirection: "column" }}>
                        <span
                          className="skills"
                          style={{
                            padding: "0px 0px 10px 0px",
                          }}
                        >
                          Languages
                        </span>
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "row",
                            justifyContent: "space-around",
                            paddingBottom: "15px",
                          }}
                        >
                          <img style={{ height: "25px" }} src={clanguage}></img>
                          <img style={{ height: "25px" }} src={python}></img>
                          <img style={{ height: "25px" }} src={java}></img>
                        </div>
                        <span
                          className="skills"
                          style={{
                            paddingBottom: "15px",
                          }}
                        >
                          Web Dev
                        </span>
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "row",
                            justifyContent: "space-around",
                            paddingBottom: "15px",
                          }}
                        >
                          <img style={{ height: "25px" }} src={linux}></img>

                          <img style={{ height: "25px" }} src={mysql}></img>
                          <img style={{ height: "25px" }} src={node}></img>
                          <img style={{ height: "25px" }} src={react}></img>
                        </div>
                        <span
                          className="skills"
                          style={{
                            paddingBottom: "15px",
                          }}
                        >
                          Networking tools
                        </span>
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "row",
                            justifyContent: "space-around",
                            paddingBottom: "15px",
                          }}
                        >
                          <img style={{ height: "25px" }} src={wireshark}></img>

                        </div>
                        <span
                          className="skills"
                          style={{
                            paddingBottom: "15px",
                          }}
                        >
                          Other Technologies
                        </span>
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "row",
                            justifyContent: "space-around",
                            paddingBottom: "15px",
                          }}
                        >
                          <img style={{ height: "25px" }} src={latex}></img>
                          <img style={{ height: "25px" }} src={git}></img>
                        </div>
                      </div>
                    </div>
                  )}
                </Grid>

              </Grid>
            </div> */}
          </span>
        </div>

        <div
          className="firstbox"
          onMouseEnter={() => {
            setHover1(true);
            // setProjects(true);
            // setArts(false);
          }}
          onMouseLeave={() => {
            setHover1(false);
            // setProjects(false);
          }}
          onClick={() => {
            handleProjects();
          }}
          style={{
            width: "100%",
            height: "150px",
            background: "white",
            display: "flex",
            flexDirection: "row-reverse",
            overflow: "hidden",
          }}
        >
          <div className="heading" style={styles}>
            <div
              style={{
                display: "flex",
                float: "right",
                padding: "20px",
                // width: "200px",
                // height: "200px",
              }}
            >
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  opacity: 0.6,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  opacity: 0.6,

                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
                }}
                src={image21}
              />
              <Box
                component="img"
                sx={{
                  width: 200,
                  height: 110,
                  marginRight: 10,
                  // backgroundColor: "black",
                  objectFit: "cover",
                  opacity: 0.6,

                  "&:hover": {
                    backgroundColor: "orange",
                    opacity: [0.9, 0.8, 0.7],
                  },
